import Link from 'next/link'
import clsx from 'clsx'

export default function RequestCard({req}){
  return (
    <Link href={`/requests/${req.id}`} className={clsx('p-4 rounded-lg shadow-sm glass block hover:scale-[1.01] transition-transform')}> 
      <div className="flex justify-between items-start">
        <div>
          <div className="text-sm text-gray-500">{req.type} • {req.priority}</div>
          <div className="font-semibold text-lg">{req.patientName} <span className="text-xs text-gray-400">{req.id}</span></div>
        </div>
        <div className="text-sm text-right">
          <div className="text-gray-600">{req.currentDept}</div>
          <div className="text-xs mt-1">{req.status}</div>
        </div>
      </div>
    </Link>
  )
}
